UPDATE lib_stock
SET stock = stock - #{amount},
    current_stock = current_stock - #{amount},
    update_time = CURRENT_TIMESTAMP
WHERE isbn = #{isbn}
  AND stock >= #{amount}
  AND current_stock >= #{amount}

UPDATE lib_stock
SET current_stock = current_stock - #{amount},
    update_time = CURRENT_TIMESTAMP
WHERE isbn = #{isbn}
  AND current_stock >= #{amount}
